 3→import dagger.hilt.android.lifecycle.HiltViewModel
 4→import kotlinx.coroutines.CoroutineDispatcher
 5→import kotlinx.coroutines.flow.MutableSharedFlow
 6→import kotlinx.coroutines.flow.MutableStateFlow
 7→import kotlinx.coroutines.flow.asStateFlow
 8→import kotlinx.coroutines.flow.update
 9→import org.wordpress.android.modules.BG_THREAD
10→import org.wordpress.android.ui.bloggingprompts.promptslist.mapper.BloggingPromptsListItemModelMapper
11→import org.wordpress.android.ui.bloggingprompts.promptslist.model.BloggingPromptsListItemModel
12→import org.wordpress.android.ui.bloggingprompts.promptslist.usecase.FetchBloggingPromptsListUseCase
13→import org.wordpress.android.util.NetworkUtilsWrapper
14→import org.wordpress.android.viewmodel.ScopedViewModel
15→import javax.inject.Inject
16→import javax.inject.Named
17→
18→@HiltViewModel
19→class BloggingPromptsListViewModel @Inject constructor(
20→    private val fetchBloggingPromptsList: FetchBloggingPromptsListUseCase,
21→    private val itemModelMapper: BloggingPromptsListItemModelMapper,
22→    private val tracker: BloggingPromptsListAnalyticsTracker,
23→    private val networkUtilsWrapper: NetworkUtilsWrapper,
24→    @Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
25→) : ScopedViewModel(bgDispatcher) {
26→    private val _uiStateFlow = MutableStateFlow<UiState>(UiState.None)
27→    val uiStateFlow = _uiStateFlow.asStateFlow()
28→
29→    private val _actionEvents = MutableSharedFlow<ActionEvent>()
30→    val actionEvents = _actionEvents
31→
32→    fun onScreenShown() {
33→        tracker.trackScreenShown()
34→        fetchPrompts()
35→    }
36→
37→    private fun fetchPrompts() {
38→        launch {
39→            if (!networkUtilsWrapper.isNetworkAvailable()) {
40→                _uiStateFlow.update { UiState.NetworkError }
41→                return@launch
42→            }
43→
44→            _uiStateFlow.update { UiState.Loading }
45→
46→            fetchBloggingPromptsList.execute()
47→                .onSuccess { prompts ->
48→                    _uiStateFlow.update { UiState.Content(prompts.map(itemModelMapper::toUiModel)) }
49→                }
50→                .onFailure {
51→                    _uiStateFlow.update { UiState.FetchError }
52→                }
53→        }
54→    }
55→
56→    fun onPromptListItemClicked(itemModel: BloggingPromptsListItemModel) {
57→        tracker.trackItemClicked()
58→        launch {
59→            _actionEvents.emit(ActionEvent.OpenEditor(itemModel.id))
60→        }
61→    }
62→
63→    sealed interface UiState {
64→        object None : UiState
65→        object Loading : UiState
66→        data class Content(val content: List<BloggingPromptsListItemModel>) : UiState
67→        object FetchError : UiState
68→        object NetworkError : UiState
69→    }
70→
71→    sealed interface ActionEvent {
72→        data class OpenEditor(val bloggingPromptId: Int) : ActionEvent
73→    }
74→}
