403→    public static void sharePost(Context context, ReaderPost post) throws ActivityNotFoundException {
404→        String url = (post.hasShortUrl() ? post.getShortUrl() : post.getUrl());
405→
406→        Intent intent = new Intent(Intent.ACTION_SEND);
407→        intent.setType("text/plain");
408→        intent.putExtra(Intent.EXTRA_TEXT, url);
409→        intent.putExtra(Intent.EXTRA_SUBJECT, post.getTitle());
410→
411→        context.startActivity(Intent.createChooser(intent, context.getString(R.string.share_link)));
412→    }
