360→            mUploadUtilsWrapper.onPostUploadedSnackbarHandler(
361→                    this,
362→                    findViewById(R.id.coordinator),
363→                    event.isError(),
364→                    event.isFirstTimePublish,
365→                    event.post,
366→                    null,
367→                    site);
368→        }
369→    }
