 832→    private void resumeFollowedSite(Site currentSite) {
 833→        ReaderBlog blog = currentSite.getBlog();
 834→        boolean isSiteStillAvailable = false;
 835→
 836→        if (blog != null) {
 837→            if ((blog.hasFeedUrl() && ReaderBlogTable.isFollowedFeed(blog.feedId))
 838→                || ReaderBlogTable.isFollowedBlog(blog.blogId)) {
 839→                isSiteStillAvailable = true;
 840→            }
 841→        }
 842→
 843→        if (isSiteStillAvailable) {
 844→            refreshPosts();
 845→        } else {
 846→            if (isFilterableScreen()) {
 847→                mSubFilterViewModel.setDefaultSubfilter();
 848→            }
 849→        }
 850→    }
