 870→    @Override
 871→    public void onStart() {
 872→        super.onStart();
 873→        mDispatcher.register(this);
 874→        EventBus.getDefault().register(this);
 875→
 876→        reloadTags();
 877→
 878→        // purge database and update followed tags/blog if necessary - note that we don't purge unless
 879→        // there's a connection to avoid removing posts the user would expect to see offline
 880→        if (getPostListType() == ReaderPostListType.TAG_FOLLOWED && NetworkUtils.isNetworkAvailable(getActivity())) {
 881→            purgeDatabaseIfNeeded();
 882→        }
