416→    private static boolean defaultTagFoundAndAdded(
417→            Map<String, TagInfo> defaultTagInfos,
418→            ReaderTag tag,
419→            Map<String, ReaderTag> defaultTags
420→    ) {
421→        boolean foundAndAdded = false;
422→
423→        for (String key : defaultTagInfos.keySet()) {
424→            if (defaultTagInfos.get(key).isDesiredTag(tag)) {
425→                if (putIfAbsentDone(defaultTags, key, tag)) {
426→                    foundAndAdded = true;
427→                }
428→                break;
429→            }
430→        }
431→
432→        return foundAndAdded;
433→    }
