 226→    /*
 227→     * purge table of unattached/older posts - no need to wrap this in a transaction since it's
 228→     * only called from ReaderDatabase.purge() which already creates a transaction
 229→     */
 230→    protected static int purge(SQLiteDatabase db) {
 231→        // delete posts attached to tags that no longer exist
 232→        int numDeleted = db.delete("tbl_posts", "tag_name NOT IN (SELECT DISTINCT tag_name FROM tbl_tags)", null);
 233→
 234→        // delete excess posts on a per-tag basis
 235→        ReaderTagList tags = ReaderTagTable.getAllTags();
 236→        for (ReaderTag tag : tags) {
 237→            numDeleted += purgePostsForTag(db, tag);
 238→        }
 239→
 240→        numDeleted += purgeUnbookmarkedPostsWithBookmarkTag();
 241→
 242→        // delete search results
 243→        numDeleted += purgeSearchResults(db);
 244→        return numDeleted;
 245→    }
 246→
 247→    /**
 248→     * When the user unbookmarks a post, we keep the row in the database, but we just change the is_bookmarked flag
 249→     * to false, so we can show "undo" items in the saved posts list. This method purges database from such rows.
 250→     */
 251→    public static int purgeUnbookmarkedPostsWithBookmarkTag() {
 252→        int numDeleted = 0;
 253→        ReaderTagList tags = ReaderTagTable.getAllTags();
 254→        for (ReaderTag tag : tags) {
 255→            if (tag.isBookmarked()) {
 256→                // delete posts which has a bookmark tag but is_bookmarked flag is false
 257→                String[] args = {tag.getTagSlug(), Integer.toString(tag.tagType.toInt())};
 258→                numDeleted += ReaderDatabase.getWritableDb()
 259→                                            .delete("tbl_posts", "tag_name=? AND tag_type=? AND is_bookmarked=0", args);
 260→            }
 261→        }
 262→        if (numDeleted > 0) {
 263→            EventBus.getDefault().post(ReaderPostTableActionEnded.INSTANCE);
 264→        }
 265→        return numDeleted;
 266→    }
