 373→        String columns = (excludeTextColumn ? COLUMN_NAMES_NO_TEXT : "*");
 374→        String sql = "SELECT " + columns + " FROM tbl_posts WHERE " + where + " LIMIT 1";
 375→
 376→        Cursor c = ReaderDatabase.getReadableDb().rawQuery(sql, args);
 377→        try {
 378→            if (!c.moveToFirst()) {
 379→                return null;
 380→            }
 381→            return getPostFromCursor(c);
 382→        } finally {
 383→            SqlUtils.closeCursor(c);
 384→        }
 385→    }
