222→    private void shareSite() {
223→        ReaderBlog blog = ReaderBlogTable.getBlogInfo(mSiteId);
224→
225→        if (blog != null && blog.hasUrl()) {
226→            Intent intent = new Intent(Intent.ACTION_SEND);
227→            intent.setType("text/plain");
228→            intent.putExtra(Intent.EXTRA_TEXT, blog.getUrl());
229→
230→            if (blog.hasName()) {
231→                intent.putExtra(Intent.EXTRA_SUBJECT, blog.getName());
232→            }
233→
234→            try {
235→                mReaderTracker.trackBlog(
236→                        AnalyticsTracker.Stat.READER_SITE_SHARED,
237→                        blog.blogId,
238→                        blog.feedId,
239→                        blog.isFollowing,
240→                        mSource
241→                );
242→                startActivity(Intent.createChooser(intent, getString(R.string.share_link)));
243→            } catch (ActivityNotFoundException exception) {
244→                ToastUtils.showToast(ReaderPostListActivity.this, R.string.reader_toast_err_share_intent);
245→            }
246→        } else {
247→            ToastUtils.showToast(ReaderPostListActivity.this, R.string.reader_toast_err_share_intent);
248→        }
249→    }
