356→    @Subscribe(threadMode = ThreadMode.MAIN)
357→    public void onPostUploaded(OnPostUploaded event) {
358→        SiteModel site = mSiteStore.getSiteByLocalId(mSelectedSiteRepository.getSelectedSiteLocalId());
