 706→    private void changeReaderMode(ReaderModeInfo readerModeInfo, boolean onlyOnChanges) {
 707→        boolean changesDetected = false;
 708→
 709→        if (onlyOnChanges) {
 710→            changesDetected = (readerModeInfo.getTag() != null
 711→                               && mCurrentTag != null
 712→                               && !readerModeInfo.getTag().equals(mCurrentTag))
 713→                              || (mPostListType != readerModeInfo.getListType())
 714→                              || (mCurrentBlogId != readerModeInfo.getBlogId())
 715→                              || (mCurrentFeedId != readerModeInfo.getFeedId())
 716→                              || (readerModeInfo.isFirstLoad());
 717→
 718→            if (changesDetected && !readerModeInfo.isFirstLoad()) {
 719→                trackTagLoaded(readerModeInfo.getTag());
 720→            }
 721→        }
 722→
 723→        if (onlyOnChanges && !changesDetected) return;
 724→
 725→        if (readerModeInfo.getTag() != null) {
 726→            mCurrentTag = readerModeInfo.getTag();
 727→        }
 728→
 729→        mPostListType = readerModeInfo.getListType();
 730→        mCurrentBlogId = readerModeInfo.getBlogId();
 731→        mCurrentFeedId = readerModeInfo.getFeedId();
 732→
 733→        resetPostAdapter(mPostListType);
 734→        if (readerModeInfo.getRequestNewerPosts()) {
 735→            updatePosts(false);
 736→        }
 737→    }
