 751→    @Override
 752→    public void onResume() {
 753→        super.onResume();
 754→        /*
 755→         * This is a workaround for https://github.com/wordpress-mobile/WordPress-Android/issues/11985.
 756→         * The RecyclerView doesn't get redrawn correctly when the adapter finishes its initialization in onStart.
 757→         */
 758→        getPostAdapter().notifyDataSetChanged();
 759→        if (mWasPaused) {
 760→            AppLog.d(T.READER, "reader post list > resumed from paused state");
 761→            mWasPaused = false;
 762→
 763→            Site currentSite;
 764→
 765→            if (getPostListType() == ReaderPostListType.TAG_FOLLOWED) {
 766→                resumeFollowedTag();
 767→            } else if ((currentSite = getSiteIfBlogPreview()) != null) {
 768→                resumeFollowedSite(currentSite);
 769→            } else {
 770→                refreshPosts();
 771→            }
 772→
 773→            if (mIsTopLevel) {
 774→                // Remove sticky event if not consumed
 775→                EventBus.getDefault().removeStickyEvent(ReaderEvents.TagAdded.class);
 776→            }
 777→
 778→            // if the user tapped a site to show site preview, it's possible they also changed the follow
 779→            // status so tell the search adapter to check whether it has the correct follow status
 780→            if (isSearching() && mLastTappedSiteSearchResult != null) {
 781→                getSiteSearchAdapter().checkFollowStatusForSite(mLastTappedSiteSearchResult);
 782→                mLastTappedSiteSearchResult = null;
 783→            }
 784→
 785→            if (isSearching()) {
 786→                return;
 787→            }
 788→        }
 789→
 790→        if (shouldShowEmptyViewForSelfHostedCta()) {
 791→            setEmptyTitleDescriptionAndButton(false);
 792→            showEmptyView();
 793→        }
 794→
 795→        mViewModel.onFragmentResume(mIsTopLevel, isSearching(), isFilterableScreen(),
 796→                isFilterableScreen() ? mSubFilterViewModel.getCurrentSubfilterValue() : null);
 797→    }
