 800→     * called when fragment is resumed and we're looking at posts in a followed tag
 801→     */
 802→    private void resumeFollowedTag() {
 803→        TagAdded addedTag = EventBus.getDefault().getStickyEvent(ReaderEvents.TagAdded.class);
 804→        if (isFollowingScreen() && addedTag != null) {
 805→            EventBus.getDefault().removeStickyEvent(addedTag);
 806→            // user just added a tag so switch to it.
 807→            ReaderTag newTag = ReaderUtils.getTagFromTagName(addedTag.getTagName(), ReaderTagType.FOLLOWED);
 808→            mSubFilterViewModel.setSubfilterFromTag(newTag);
 809→        } else if (isFollowingScreen() && !ReaderTagTable.tagExists(getCurrentTag())) {
 810→            // user just removed a tag which was selected in the subfilter
 811→            mSubFilterViewModel.setDefaultSubfilter();
 812→        } else {
 813→            // otherwise, refresh posts to make sure any changes are reflected and auto-update
 814→            // posts in the current tag if it's time
 815→            refreshPosts();
 816→            updateCurrentTagIfTime();
 817→        }
 818→    }
