1356→    private void submitSearchQuery(@NonNull String query) {
1357→        if (!isAdded()) {
1358→            return;
1359→        }
1360→
1361→        mSearchView.clearFocus(); // this will hide suggestions and the virtual keyboard
1362→        hideSearchMessage();
1363→        hideSearchSuggestions();
1364→
1365→        if (!NetworkUtils.isNetworkAvailable(getContext())) {
1366→            showEmptyView();
1367→        }
1368→
1369→        // remember this query for future suggestions
1370→        String trimQuery = query.trim();
1371→        ReaderSearchTable.addOrUpdateQueryString(trimQuery);
1372→
1373→        // remove cached results for this search - search results are ephemeral so each search
1374→        // should be treated as a "fresh" one
1375→        ReaderTag searchTag = ReaderUtils.getTagForSearchQuery(trimQuery);
1376→        ReaderPostTable.deletePostsWithTag(searchTag);
1377→
1378→        mPostAdapter.setCurrentTag(searchTag);
1379→        mCurrentSearchQuery = trimQuery;
1380→        updatePostsInCurrentSearch(0);
1381→        updateSitesInCurrentSearch(0);
1382→
1383→        toggleJetpackBannerIfEnabled(false, false);
1384→
1385→        // track that the user performed a search
1386→        if (!trimQuery.equals("")) {
1387→            mReaderTracker.trackQuery(AnalyticsTracker.Stat.READER_SEARCH_PERFORMED, trimQuery);
1388→        }
1389→    }
