1402→
1403→        ReaderSiteSearchAdapter adapter = getSiteSearchAdapter();
1404→        if (event.isError()) {
1405→            adapter.clear();
1406→        } else if (StringUtils.equals(event.searchTerm, mCurrentSearchQuery)) {
1407→            adapter.setCanLoadMore(event.canLoadMore);
1408→            if (event.offset == 0) {
1409→                adapter.setSiteList(event.sites);
1410→            } else {
1411→                adapter.addSiteList(event.sites);
1412→            }
1413→            if (mSiteSearchRestorePosition > 0) {
