1965→    /*
1966→     * called by post adapter to load older posts when user scrolls to the last post
1967→     */
1968→    private final ReaderActions.DataRequestedListener mDataRequestedListener =
1969→            new ReaderActions.DataRequestedListener() {
1970→                @Override
1971→                public void onRequestData() {
1972→                    // skip if update is already in progress
1973→                    if (isUpdating()) {
1974→                        return;
1975→                    }
1976→
1977→                    // request older posts unless we already have the max # to show
1978→                    switch (getPostListType()) {
1979→                        case TAG_FOLLOWED:
1980→                            // fall through to TAG_PREVIEW
1981→                        case TAG_PREVIEW:
1982→                            if (ReaderPostTable.getNumPostsWithTag(mCurrentTag)
1983→                                < ReaderConstants.READER_MAX_POSTS_TO_DISPLAY) {
1984→                                // request older posts
1985→                                updatePostsWithTag(getCurrentTag(), UpdateAction.REQUEST_OLDER);
1986→                                mReaderTracker.track(AnalyticsTracker.Stat.READER_INFINITE_SCROLL);
1987→                            }
1988→                            break;
1989→
1990→                        case BLOG_PREVIEW:
1991→                            int numPosts;
1992→                            if (mCurrentFeedId != 0) {
1993→                                numPosts = ReaderPostTable.getNumPostsInFeed(mCurrentFeedId);
1994→                            } else {
1995→                                numPosts = ReaderPostTable.getNumPostsInBlog(mCurrentBlogId);
1996→                            }
1997→                            if (numPosts < ReaderConstants.READER_MAX_POSTS_TO_DISPLAY) {
1998→                                updatePostsInCurrentBlogOrFeed(UpdateAction.REQUEST_OLDER);
1999→                                mReaderTracker.track(AnalyticsTracker.Stat.READER_INFINITE_SCROLL);
2000→                            }

2000→                            }
2001→                            break;
2002→
2003→                        case SEARCH_RESULTS:
2004→                            ReaderTag searchTag = ReaderUtils.getTagForSearchQuery(mCurrentSearchQuery);
2005→                            int offset = ReaderPostTable.getNumPostsWithTag(searchTag);
2006→                            if (offset < ReaderConstants.READER_MAX_POSTS_TO_DISPLAY) {
2007→                                updatePostsInCurrentSearch(offset);
2008→                                mReaderTracker.track(AnalyticsTracker.Stat.READER_INFINITE_SCROLL);
2009→                            }
2010→                            break;
2011→                    }
2012→                }
2013→            };
