2016→        if (mPostAdapter == null) {
2017→            AppLog.d(T.READER, "reader post list > creating post adapter");
2018→            Context context = WPActivityUtils.getThemedContext(getActivity());
2019→            mPostAdapter = new ReaderPostAdapter(
2020→                    context,
2021→                    getPostListType(),
2022→                    mImageManager,
2023→                    mUiHelpers,
2024→                    mIsTopLevel
2025→            );
