1313→                        Long.toString(post.postId),
1314→                        Integer.toString(ReaderTagType.BOOKMARKED.toInt())});
1315→                db.setTransactionSuccessful();
1316→            } finally {
1317→                db.endTransaction();
1318→            }
1319→        }
